const rows = $input.all();

function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return '';
}

function pickCommentList(payload) {
  const candidates = [
    payload?.data?.comments,
    payload?.data?.comment_list,
    payload?.data?.list,
    payload?.data?.items,
    payload?.comments,
    payload?.comment_list,
    payload?.list,
    payload?.items,
  ];

  for (const candidate of candidates) {
    if (Array.isArray(candidate)) return candidate;
  }

  if (Array.isArray(payload?.data?.data)) return payload.data.data;
  if (Array.isArray(payload?.data?.comments?.items)) return payload.data.comments.items;

  return [];
}

const results = [];

for (const item of rows) {
  const payload = item.json || {};
  const cfg = $('Set API and Comment Parameters').first().json;
  const data = payload.data || {};
  const maxComments = Math.max(1, Number(cfg.maxComments || 20));
  const comments = pickCommentList(payload).slice(0, maxComments);

  const normalized = comments.map((comment, index) => {
    const user = comment.user || comment.author || comment.comment_user_info || {};

    return {
      index: index + 1,
      commentId: firstDefined(comment.id, comment.comment_id, comment.commentId),
      noteId: firstDefined(comment.note_id, comment.noteId, cfg.noteId),
      content: firstDefined(comment.content, comment.text, comment.desc, comment.comment),
      likeCount: Number(firstDefined(comment.like_count, comment.likes, comment.liked_count, 0) || 0),
      replyCount: Number(firstDefined(comment.sub_comment_count, comment.reply_count, comment.replyCount, 0) || 0),
      createTime: firstDefined(comment.create_time, comment.time, comment.publish_time),
      ipLocation: firstDefined(comment.ip_location, comment.location),
      status: firstDefined(comment.status, 0),
      hidden: Boolean(comment.hidden ?? false),
      liked: Boolean(comment.liked ?? false),
      collected: Boolean(comment.collected ?? false),
      showType: firstDefined(comment.show_type),
      commentType: firstDefined(comment.comment_type),
      trackId: firstDefined(comment.track_id),
      authorId: firstDefined(user.user_id, user.userid, user.id),
      authorName: firstDefined(user.nickname, user.name),
      authorRedId: firstDefined(user.red_id, user.redId),
      authorAvatar: firstDefined(user.images, user.image, user.avatar),
      atUsers: Array.isArray(comment.at_users) ? comment.at_users : [],
      subComments: Array.isArray(comment.sub_comments) ? comment.sub_comments : [],
      hashTags: Array.isArray(comment.hash_tags) ? comment.hash_tags : [],
      rawComment: comment,
    };
  });

  results.push({
    json: {
      noteId: cfg.noteId,
      requestedMaxComments: maxComments,
      extractedCount: normalized.length,
      totalCommentCount: Number(firstDefined(data.comment_count, data.comments_count, normalized.length) || 0),
      level1CommentCount: Number(firstDefined(data.comment_count_l1, normalized.length) || 0),
      hasMore: Boolean(data.has_more ?? false),
      nextCursor: firstDefined(data.cursor),
      currentSortStrategy: firstDefined(data.current_sort_strategy),
      allSortStrategies: Array.isArray(data.all_sort_strategies) ? data.all_sort_strategies : [],
      userId: firstDefined(data.user_id),
      pageContext: firstDefined(data.page_context),
      comments: normalized,
      raw: payload,
    }
  });
}

return results;
